-- ----------------------------
-- Table structure for sys_logs
-- ----------------------------
DROP TABLE IF EXISTS `sys_logs`;
CREATE TABLE `sys_logs`  (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `describe` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL COMMENT '功能描述',
  `method` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL COMMENT '方法',
  `params` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL COMMENT '参数',
  `ip` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL COMMENT '请求ip',
  `time` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL COMMENT '耗时',
  `user_id` int(11) NULL DEFAULT NULL COMMENT '用户id',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4109 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_bin ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of sys_logs
-- ----------------------------
